import{_ as e,a as t}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Safety/user-rate-limits.md","filePath":"id-ID/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),n={name:"id-ID/Safety/user-rate-limits.md"};function r(o,a,u,p,m,g){return d(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits mengontrol seberapa sering regular users atau visitors dapat upload files dari homepage. Ini membantu mencegah public upload pages disalahgunakan.</p><p>Feature ini hanya memengaruhi homepage uploads. Admin uploads dan uploads menggunakan API Tokens tidak dibatasi oleh user rate limits.</p><h2 id="di-mana-mengonfigurasinya" tabindex="-1">Di Mana Mengonfigurasinya <a class="header-anchor" href="#di-mana-mengonfigurasinya" aria-label="Permalink to &quot;Di Mana Mengonfigurasinya&quot;">​</a></h2><p>Buka admin panel, lalu masuk ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="mengaktifkan-rate-limits" tabindex="-1">Mengaktifkan Rate Limits <a class="header-anchor" href="#mengaktifkan-rate-limits" aria-label="Permalink to &quot;Mengaktifkan Rate Limits&quot;">​</a></h2><p>Setelah <code>Enable Rate Limits</code> dinyalakan, ImgBed track recent uploads berdasarkan uploader IP address.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Seberapa jauh upload records dihitung ke belakang.</td></tr><tr><td>Max file count</td><td>20</td><td>Jumlah files maksimum yang diizinkan dalam detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Ukuran maksimum satu file.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Total upload size maksimum dalam detection window.</td></tr></tbody></table><p>Contohnya, dengan 1.5 hour window, 20 files, 20 MB per file, dan 200 MB total, uploads dari IP yang sama akan diblock begitu melewati salah satu configured limit.</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> memblokir regular users atau visitors agar tidak upload file categories yang dipilih.</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif, dan image files sejenis</td></tr><tr><td>Videos</td><td>mp4, webm, mov, dan video files sejenis</td></tr><tr><td>Audio</td><td>mp3, flac, wav, dan audio files sejenis</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx, dan document files sejenis</td></tr><tr><td>Other</td><td>Files di luar categories di atas, seperti zip, rar, exe, apk</td></tr></tbody></table><p>Secara default, tidak ada type yang dipilih, artinya allowed.</p><p>Mengklik type akan membuatnya highlight, artinya type tersebut blocked.</p><p>Jika <code>Other</code> dipilih, visitors yang upload zip atau rar files akan diblock dan diberi tahu bahwa file type ini tidak didukung.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>Saat limit triggered, users melihat message yang sesuai:</p><p><img src="'+t+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File terlalu besar dan sebaiknya dicompress sebelum upload.</td></tr><tr><td>File type blocked</td><td>File type ini tidak didukung. Hapus file tersebut dan coba lagi.</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads terlalu sering, dengan retry time ditampilkan.</td></tr><tr><td>Total size too high</td><td>Recent total upload size terlalu tinggi, dengan retry time ditampilkan.</td></tr></tbody></table><h2 id="kapan-perlu-enable" tabindex="-1">Kapan Perlu Enable <a class="header-anchor" href="#kapan-perlu-enable" aria-label="Permalink to &quot;Kapan Perlu Enable&quot;">​</a></h2><p>Enable user rate limits jika upload homepage Anda publicly accessible.</p><p>Alasan umum:</p><ul><li>Anda khawatir dengan scripted bulk uploads.</li><li>Anda ingin membatasi large visitor uploads.</li><li>Anda hanya ingin regular users upload images, bukan archives atau installers.</li><li>Anda ingin public upload tetap tersedia sambil mengontrol resource usage.</li></ul><p>Jika site hanya untuk Anda sendiri, atau hanya administrators yang bisa upload, biarkan disabled.</p>',28)])])}const k=i(n,[["render",r]]);export{b as __pageData,k as default};
